#!/bin/bash
# Stage 07 - coturn TURN/STUN server for WebRTC (Jitsi + Matrix)
set -euo pipefail

echo "==> Installing coturn..."
export DEBIAN_FRONTEND=noninteractive
apt-get -y install coturn

echo "==> Enabling coturn service..."
# Debian package disables the service by default
sed -i 's/^#TURNSERVER_ENABLED=1/TURNSERVER_ENABLED=1/' /etc/default/coturn 2>/dev/null || \
  echo "TURNSERVER_ENABLED=1" >> /etc/default/coturn

LXC_IP=$(hostname -I | awk '{print $1}')

echo "==> Writing coturn configuration..."
cat > /etc/turnserver.conf <<EOF
# coturn configuration - generated by unraid-lxc-matrix
# TURN/STUN for Matrix + Jitsi WebRTC

# Listening ports
listening-port=3478
tls-listening-port=5349

# Relay IPs - LXC IP
listening-ip=${LXC_IP}
relay-ip=${LXC_IP}

# External IP (set this to your public IP if behind NAT)
# external-ip=<PUBLIC_IP>/<LXC_IP>

# Authentication
lt-cred-mech
use-auth-secret
static-auth-secret=${TURN_SECRET}

# Realm
realm=${DOMAIN}

# Log
log-file=/var/log/coturn/turn.log
log-binding-and-attribute
verbose

# Security
no-loopback-peers
no-multicast-peers
denied-peer-ip=10.0.0.0-10.255.255.255
denied-peer-ip=192.168.0.0-192.168.255.255
denied-peer-ip=172.16.0.0-172.31.255.255

# TLS certificates (Nginx handles TLS termination, coturn uses plain TURN internally)
# Uncomment and set paths after cert provisioning:
# cert=/etc/letsencrypt/live/${DOMAIN}/fullchain.pem
# pkey=/etc/letsencrypt/live/${DOMAIN}/privkey.pem

# UDP relay ports (for media traffic)
min-port=49152
max-port=65535

# Disable cleartext TCP connections (use TURN-over-TCP)
no-tcp-relay

# Fingerprint
fingerprint

# CLI for diagnostics
cli-ip=127.0.0.1
cli-port=5766
cli-password=${TURN_SECRET}
EOF

mkdir -p /var/log/coturn
chown turnserver:turnserver /var/log/coturn 2>/dev/null || true

echo "==> Enabling and starting coturn..."
systemctl daemon-reload
systemctl enable coturn
systemctl start coturn

echo "==> Verifying coturn is listening on 3478..."
sleep 2
if ss -ulnp | grep -q ':3478'; then
  echo "   coturn is listening on UDP 3478: OK"
else
  echo "   WARNING: coturn may not be listening - check: journalctl -u coturn"
fi

echo "Completed Stage 07 - coturn"
